import{_ as t,c as a,o as r,a2 as n}from"./chunks/framework.CIiVzG-O.js";const h=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"guide/introduction.md","filePath":"guide/introduction.md","lastUpdated":1781417556000}'),o={name:"guide/introduction.md"};function i(s,e,l,d,u,m){return r(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><h2 id="about-petreminder" tabindex="-1">About PetReminder <a class="header-anchor" href="#about-petreminder" aria-label="Permalink to &quot;About PetReminder&quot;">​</a></h2><p>PetReminder is a macOS desktop application that brings cute pets to your screen when reminders are due. Set custom reminders, and when the time comes, an adorable cat or dog appears on your desktop to keep you company, making sure you never miss important moments.</p><p>PetReminder is lightweight, native, and optimized for macOS — built for performance and low resource usage.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><h3 id="🐱-desktop-pet-companions" tabindex="-1">🐱 <strong>Desktop Pet Companions</strong> <a class="header-anchor" href="#🐱-desktop-pet-companions" aria-label="Permalink to &quot;🐱 **Desktop Pet Companions**&quot;">​</a></h3><p>When a reminder fires, a cute pet appears on your desktop. Watch them interact, play, and keep you company.</p><h3 id="⏰-smart-reminders" tabindex="-1">⏰ <strong>Smart Reminders</strong> <a class="header-anchor" href="#⏰-smart-reminders" aria-label="Permalink to &quot;⏰ **Smart Reminders**&quot;">​</a></h3><p>Customize reminder times and messages. Flexible scheduling for daily tasks, special events, and recurring needs.</p><h3 id="🎨-customizable-pets" tabindex="-1">🎨 <strong>Customizable Pets</strong> <a class="header-anchor" href="#🎨-customizable-pets" aria-label="Permalink to &quot;🎨 **Customizable Pets**&quot;">​</a></h3><p>Adjust pet appearance, behaviors, and sound effects. Make each pet uniquely yours.</p><h3 id="🛍️-premium-pets-iap" tabindex="-1">🛍️ <strong>Premium Pets (IAP)</strong> <a class="header-anchor" href="#🛍️-premium-pets-iap" aria-label="Permalink to &quot;🛍️ **Premium Pets (IAP)**&quot;">​</a></h3><p>Unlock additional pet breeds through in-app purchase:</p><ul><li><strong>Ragdoll Cat</strong> — Elegant and graceful</li><li><strong>British Shorthair Cat</strong> — Chubby and adorable</li><li><strong>Shiba Inu</strong> — Playful and lively</li><li><strong>Corgi</strong> — Energetic with short legs</li><li><strong>Husky</strong> — Expressive and handsome</li></ul><h3 id="🎯-native-performance" tabindex="-1">🎯 <strong>Native Performance</strong> <a class="header-anchor" href="#🎯-native-performance" aria-label="Permalink to &quot;🎯 **Native Performance**&quot;">​</a></h3><p>Optimized for macOS with minimal resource usage. PetReminder runs smoothly in the background without slowing down your Mac.</p><h2 id="system-requirements" tabindex="-1">System Requirements <a class="header-anchor" href="#system-requirements" aria-label="Permalink to &quot;System Requirements&quot;">​</a></h2><ul><li><strong>Operating System</strong>: macOS Monterey (12) or later</li><li><strong>CPU</strong>: Apple Silicon (M-series) or Intel (64-bit)</li><li><strong>Memory</strong>: 4GB RAM minimum, 8GB recommended</li><li><strong>Storage</strong>: ~200 MB for installation</li></ul><h2 id="supported-languages" tabindex="-1">Supported Languages <a class="header-anchor" href="#supported-languages" aria-label="Permalink to &quot;Supported Languages&quot;">​</a></h2><p>PetReminder supports English and Chinese (Simplified), with more languages planned.</p><h2 id="getting-started" tabindex="-1">Getting Started <a class="header-anchor" href="#getting-started" aria-label="Permalink to &quot;Getting Started&quot;">​</a></h2><p>If you&#39;re new to PetReminder, start with the <a href="/guide/installation.html">Installation Guide</a> to get the application running on your Mac.</p>',22)])])}const c=t(o,[["render",i]]);export{h as __pageData,c as default};
